import React, { useEffect, useState } from "react";
import {
  Box, Typography, Card, Table, TableBody, TableCell, TableContainer,
  TableHead, TableRow, Paper, Button, CircularProgress, Tabs, Tab
} from "@mui/material";
import axios from "axios";

const API = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function AdminDashboard() {
  const [overview, setOverview] = useState({});
  const [users, setUsers] = useState([]);
  const [captains, setCaptains] = useState([]);
  const [pendingCaptains, setPendingCaptains] = useState([]);
  const [loading, setLoading] = useState(false);
  const [tab, setTab] = useState("overview");

  const token = localStorage.getItem("token");
  const headers = { Authorization: `Bearer ${token}` };

  const fetchData = async () => {
    setLoading(true);
    try {
      const [overviewRes, usersRes, captainsRes, pendingRes] = await Promise.all([
        axios.get(`${API}/api/admin/overview`, { headers }),
        axios.get(`${API}/api/admin/users`, { headers }),
        axios.get(`${API}/api/admin/captains`, { headers }),
        axios.get(`${API}/api/admin/pending-captains`, { headers }),
      ]);
      setOverview(overviewRes.data);
      setUsers(usersRes.data.users);
      setCaptains(captainsRes.data.captains);
      setPendingCaptains(pendingRes.data.pendingCaptains);
    } catch (err) {
      console.error(err);
    } finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const handleApprove = async (id) => { await axios.post(`${API}/api/admin/captain/${id}/approve`, {}, { headers }); fetchData(); };
  const handleReject = async (id) => { await axios.post(`${API}/api/admin/captain/${id}/reject`, {}, { headers }); fetchData(); };
  const handleLogout = () => { localStorage.removeItem("token"); window.location.href="/admin"; };

  if (loading) return <CircularProgress />;

  return (
    <Box p={4}>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
        <Typography variant="h4">Rider App - Admin Dashboard</Typography>
        <Button variant="contained" color="error" onClick={handleLogout}>Logout</Button>
      </Box>

      <Tabs value={tab} onChange={(e,v)=>setTab(v)} sx={{mb:3}}>
        <Tab label="Overview" value="overview" />
        <Tab label="Users" value="users" />
        <Tab label="Captains" value="captains" />
        <Tab label="Pending Captains" value="pending" />
      </Tabs>

      {tab==="overview" && (
        <Box display="flex" gap={3}>
          {Object.entries(overview).map(([key,val])=>(
            <Card key={key} sx={{p:2, minWidth:150, textAlign:"center"}}>
              <Typography variant="subtitle1">{key}</Typography>
              <Typography variant="h5">{val}</Typography>
            </Card>
          ))}
        </Box>
      )}

      {tab==="users" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell><TableCell>Email</TableCell><TableCell>Mobile</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {users.map(u=>(
                <TableRow key={u._id}>
                  <TableCell>{u.fullName}</TableCell>
                  <TableCell>{u.email}</TableCell>
                  <TableCell>{u.mobile}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {tab==="captains" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell><TableCell>Email</TableCell><TableCell>Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {captains.map(c=>(
                <TableRow key={c._id}>
                  <TableCell>{c.fullName}</TableCell>
                  <TableCell>{c.email}</TableCell>
                  <TableCell>{c.approvalStatus}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {tab==="pending" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell><TableCell>Email</TableCell><TableCell>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {pendingCaptains.map(p=>(
                <TableRow key={p._id}>
                  <TableCell>{p.fullName}</TableCell>
                  <TableCell>{p.email}</TableCell>
                  <TableCell>
                    <Button onClick={()=>handleApprove(p._id)} color="success">Approve</Button>
                    <Button onClick={()=>handleReject(p._id)} color="error">Reject</Button>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}
    </Box>
  );
}
